try {
  const result = await mcpTool.callTool('github_read_file', {
    owner: 'example',
    repo: 'project',
    path: 'README.md'
  });
  console.log(result.content);
} catch (error) {
  if (error.code === 'AUTH_REQUIRED') {
    // 需要认证，触发认证流程
    await mcpAuthTool.authenticate('github');
    // 重试调用
    const result = await mcpTool.callTool(...);
  } else if (error.code === 'RATE_LIMITED') {
    // 处理速率限制
    await wait(1000);
    // 重试调用
  } else {
    throw error;
  }
}
